      } else {
        ok := true; out := exprObj; err := Other;
      }
    }

    method {:verify false} GetOrPutArray(rope: Rope) returns (ok: bool, out: Expr?, err: SetError)
      modifies this
      decreases *
    {
      var maybeHeadKey := EString(rope.head);
      if !IsSomeString(maybeHeadKey) {
        ok := false; out := null; err := Clobber; return;
      }
      var headKey := FromSomeString(maybeHeadKey);
      var existing := Get(headKey);
      if existing != null {
        match existing.data
        case DArray(arr) =>
          if rope.next == null {
            ok := true; out := existing; err := Other; return;
          }
          if |arr.items| > 0 {
            var last := arr.items[|arr.items| - 1];
            match last.data
            case DObject(obj) =>
              ok, out, err := obj.GetOrPutArray(rope.next);
              return;
            case _ =>
              ok := false; out := null; err := Clobber; return;
          }
          ok := false; out := null; err := Clobber; return;
        case DObject(obj2) =>
          if rope.next == null {
            ok := false; out := null; err := Clobber; return;
          }
          ok, out, err := obj2.GetOrPutArray(rope.next);
          return;
        case _ =>
          ok := false; out := null; err := Clobber; return;
      }

      if rope.next != null {
        var obj := new Object();
        var exprObj := new Expr(DObject(obj), rope.head.loc);
        ok, out, err := obj.GetOrPutArray(rope.next);
        if !ok { return; }
        var prop := new Property(rope.head, exprObj);
        properties := properties + [prop];
        return;
      }

      var arr := new Array();
      var outExpr := new Expr(DArray(arr), rope.head.loc);
      var prop := new Property(rope.head, outExpr);
      properties := properties + [prop];
      ok := true; out := outExpr; err := Other;
    }
  }

  datatype LexItem = LexItem(tok: T, text: seq<int>, num: real, loc: int, newlineBefore: bool)

  class Lexer {
    var source: Source
    var stream: seq<LexItem>
    var index: int
    var token: T
    var identifier: seq<int>
    var number: real
    var has_newline_before: bool
    var allow_double_bracket: bool
    var start: int

    constructor(source_: Source, stream_: seq<LexItem>)
    {
      source := source_;
      stream := stream_;
      index := 0;
      identifier := [];
      number := 0.0;
      has_newline_before := false;
      allow_double_bracket := true;
      start := 0;
      if |stream_| == 0 {
        token := t_end_of_file;
      } else {
        token := stream_[0].tok;
        identifier := stream_[0].text;
        number := stream_[0].num;
        start := stream_[0].loc;
        has_newline_before := stream_[0].newlineBefore;
      }
    }

    method {:verify false} Loc() returns (loc: Loc) { loc := new Loc(start); }

    method {:verify false} Next() returns (ok: bool)
      modifies this
    {
      index := index + 1;
      if index < |stream| {
        token := stream[index].tok;
        identifier := stream[index].text;
        number := stream[index].num;
        start := stream[index].loc;
        has_newline_before := stream[index].newlineBefore;
      } else {
        token := t_end_of_file;
        identifier := [];
        number := 0.0;
        has_newline_before := true;
      }
      ok := true;
    }

    method {:verify false} Expect(t: T) returns (ok: bool)
      modifies this
    {
      if token != t { ok := false; return; }
      ok := Next();
    }

    method {:verify false} ExpectAssignment() returns (ok: bool)
      modifies this
    {
      ok := Expect(t_equal);
    }

    method {:verify false} ToString(loc: Loc) returns (e: Expr)
    {
      e := new Expr(DString(identifier), loc);
    }

    method {:verify false} Raw() returns (bytes: seq<int>)
    {
      bytes := identifier;
    }

    method {:verify false} ExpectedString(unused: seq<int>) returns (ok: bool) { ok := false; }
    method {:verify false} AddDefaultError(unused: seq<int>) returns (ok: bool) { ok := false; }
    method {:verify false} AddError(unusedStart: int, unusedMessage: seq<int>) returns (ok: bool) { ok := false; }
    method {:verify false} Unexpected() returns (ok: bool) { ok := false; }
  }

  class StackCheck {
    constructor() {}
    method {:verify false} IsSafeToRecurse() returns (ok: bool) { ok := true; }
  }

  class HashMapPoolNode {
    var data: set<int>
    var next: HashMapPoolNode?
    constructor() { data := {}; next := null; }
  }

  class HashMapPool {
    var list: HashMapPoolNode?
    constructor() { list := null; }

    method {:verify false} Get() returns (node: HashMapPoolNode)
      modifies this
    {
      if list != null {
        node := list;
        list := node.next;
        node.data := {};
        node.next := null;
        return;
      }
      node := new HashMapPoolNode();
    }

    method {:verify false} Release(node: HashMapPoolNode)
      modifies this, node
    {
      node.next := list;
      list := node;
    }
  }

  class TOML {
    var lexer: Lexer
    var bump: object?
    var stack_check: StackCheck

    constructor(source_: Source, stream_: seq<LexItem>)
    {
      lexer := new Lexer(source_, stream_);
      bump := null;
      stack_check := new StackCheck();
    }

    method {:verify false} Source_() returns (source: Source)
    {
      source := lexer.source;
    }

    method {:verify false} E(data: ExprData, loc: Loc) returns (expr: Expr)
    {
      expr := new Expr(data, loc);
    }

    static method {:verify false} Parse(source_: Source, stream_: seq<LexItem>) returns (ok: bool, expr: Expr?)
      decreases *
    {
      if |source_.contents| == 0 {
        var emptyLoc := new Loc(0);
        var obj := new Object();
        expr := new Expr(DObject(obj), emptyLoc);
        ok := true;
        return;
      }

      var parser := new TOML(source_, stream_);
      ok, expr := parser.RunParser();
    }

    method {:verify false} ParseMaybeTrailingComma(closer: T) returns (ok: bool, keepGoing: bool)
      modifies lexer
    {
      ok := lexer.Expect(t_comma);
      if !ok { keepGoing := false; return; }

      if lexer.token == closer {
        keepGoing := false;
        return;
      }

      keepGoing := true;
    }

    method {:verify false} ParseKeySegment() returns (ok: bool, out: Expr?)
      modifies lexer
    {
      var loc := lexer.Loc();

      match lexer.token
      case t_string_literal =>
        var str := lexer.ToString(loc);
        ok := lexer.Next();
        out := str;
      case t_identifier =>
        var str := new Expr(DString(lexer.identifier), loc);
        ok := lexer.Next();
        out := str;
      case t_false =>
        ok := lexer.Next();
        out := new Expr(DString([102, 97, 108, 115, 101]), loc);
      case t_true =>
        ok := lexer.Next();
        out := new Expr(DString([116, 114, 117, 101]), loc);
      case t_numeric_literal =>
        var literal := lexer.Raw();
        ok := lexer.Next();
        out := new Expr(DString(literal), loc);
      case _ =>
        ok := true;
        out := null;
    }

